import java.io.*;

public class CommandInjectionSecure {
    public static void main(String[] args) throws IOException {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter a command to execute: ");
        String command = reader.readLine().trim();

        // Validate user input to only allow alphanumeric characters and certain safe characters
        if (!command.matches("[a-zA-Z0-9_\\-]+")) {
            System.out.println("Invalid command. Please provide a valid command.");
            return;
        }

        // Execute the sanitized command
        Process process = Runtime.getRuntime().exec(new String[] { "ping", command });

        BufferedReader inputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
        String line;

        while ((line = inputReader.readLine()) != null) {
            System.out.println(line);
        }
    }
}

